import { Component, OnInit } from "@angular/core";
import {
  FormBuilder,
  FormControl,
  FormGroup,
  Validators,
} from "@angular/forms";
import { AlertService } from "src/app/core/services/alert.service";
import { IDocTypes } from "src/app/views/Models/References/DocTypes";
import { StaticRef } from "src/app/views/Models/References/StaticRef";
import { ReferencesService } from "src/app/core/services/references.service";
import { HttpClient } from "@angular/common/http";
import { EnvService } from "src/app/core/services/env.service";
import { InputMaskingService } from "src/app/core/services/input-masking.service";
@Component({
  selector: "app-doc-types",
  templateUrl: "./doc-types.page.html",
  styleUrls: ["./doc-types.page.scss"],
})
export class DocTypesPage implements OnInit {
  [x: string]: any;
  docTypeForm: any;
  DocDefSizeRef: StaticRef[];
  IDocScanLoc: StaticRef[];
  TCRadRefType: StaticRef[];
  DocTypeForm: FormGroup = this.formBuilder.group({
    doc_type_code: [""],
    doc_type_desc: ["", [Validators.required]],
    doc_no_pages: ["", [Validators.required]],
    doc_def_size: ["", [Validators.required]],
    doc_size_edit: [""],
    doc_scan_loc: ["", [Validators.required]],
    doc_ref_type: ["", [Validators.required]],
  });
  noWhitespaceValidator(control: FormControl) {
    const isWhitespace =
      control.value !== null &&
      (control.value || "").toString().trim().length === 0;
    const isValid = !isWhitespace;
    return isValid ? null : { whitespace: true };
  }
  constructor(
    private http: HttpClient,
    private env: EnvService,
    private formBuilder: FormBuilder,
    private alertServices: AlertService,
    private ReferencesService: ReferencesService,
    public inputMaskingService: InputMaskingService
  ) {}
  showLoader: boolean = false;
  isSubmitted: boolean = false;
  isInserting: boolean = false;
  isUpdating: boolean = false;
  disableIonSelect: boolean = false;
  DocType: IDocTypes[];
  async ngOnInit() {
    this.DocType = await this.ReferencesService.GetDocumentTypes();
    this.DocDefSizeRef = await this.ReferencesService.GetIdocDefSize();
    this.IDocScanLoc = await this.ReferencesService.GetVouchPrint();
    this.TCRadRefType = await this.ReferencesService.GetTCRadRefType();
  }
  async insertDocTypes() {
    this.isUpdating = false;
    this.isInserting = true;
    this.disableIonSelect = false;
    this.DocTypeForm.reset();
  }
  updateDocType(index: number) {
    const DocType = this.DocType[index];
    this.DocTypeForm.patchValue({
      doc_type_code: DocType.doc_type_code,
      doc_type_desc: DocType.doc_type_desc,
      doc_no_pages: Number(DocType.doc_no_pages),
      doc_def_size: DocType.doc_def_size.toString(),
      doc_size_edit: DocType.doc_size_edit == "1",
      doc_scan_loc: DocType.doc_scan_loc.toString(),
      doc_ref_type: DocType.doc_ref_type.toString(),
    });
    this.isInserting = false;
    this.isUpdating = true;
    this.disableIonSelect = true;
  }
  async deleteDocType(doc_type_code: number) {
    if (
      await this.alertServices.DeleteAlert("هل انت متاكد من مسح هذه المستند؟")
    ) {
      this.showLoader = true;
      this.http
        .post(this.env.API_URL + "api/Documents/DeleteDocType", {
          doc_type_code: doc_type_code.toString(),
        })
        .subscribe({
          next: (data) => {
            this.showLoader = false;
            this.alertServices.showAlertConfirm(" تم الحذف بنجاح", true);
          },
          error: (err) => {
            console.log(err);
            this.alertServices.showAlertError(err.error, false);
            this.showLoader = false;
          },
        });
    }
  }
  clearForms() {
    this.isInserting = false;
    this.isUpdating = false;
    this.isSubmitted = false;
    this.DocTypeForm.reset();
  }
  async submitDocTypeInsert() {
    this.showLoader = true;
    if (this.DocTypeForm.valid) {
      if (await this.alertServices.SaveAlert("هل تريد الاضافة؟"))
        this.http
          .post(this.env.API_URL + "api/Documents/InsertDocType", {
            doc_type_desc: this.DocTypeForm.value.doc_type_desc.toString(),
            doc_ref_type: this.DocTypeForm.value.doc_ref_type.toString(),
            doc_no_pages: this.DocTypeForm.value.doc_no_pages.toString(),
            doc_def_size: this.DocTypeForm.value.doc_def_size.toString(),
            doc_size_edit:
              this.DocTypeForm.value.doc_size_edit === true ? 1 : 0,
            doc_scan_loc: this.DocTypeForm.value.doc_scan_loc.toString(),
          })
          .subscribe({
            next: (data) => {
              this.showLoader = false;
              this.alertServices.showAlertConfirm(" تم الاضافة بنجاح", true);
            },
            error: (err) => {
              console.log(err);
              this.alertServices.showAlertError(err.error, false);
              this.showLoader = false;
            },
          });
    } else {
      this.alertServices.showAlertError(" يجب ادخال جميع البيانات", false);
      this.showLoader = false;
    }
  }
  async submitDocTypeUpdate() {
    this.showLoader = true;
    if (this.DocTypeForm.valid) {
      if (await this.alertServices.SaveAlert("هل تريد تعديل البيانات؟"))
        this.http
          .post(this.env.API_URL + "api/Documents/UpdateDocType", {
            doc_type_code: this.DocTypeForm.value.doc_type_code.toString(),
            doc_type_desc: this.DocTypeForm.value.doc_type_desc.toString(),
            doc_no_pages: this.DocTypeForm.value.doc_no_pages.toString(),
            doc_def_size: this.DocTypeForm.value.doc_def_size.toString(),
            doc_size_edit:
              this.DocTypeForm.value.doc_size_edit === true ? 1 : 0,
          })
          .subscribe({
            next: (data) => {
              this.showLoader = false;
              this.alertServices.showAlertConfirm(" تم التعديل بنجاح", true);
            },
            error: (err) => {
              console.log(err);
              this.alertServices.showAlertError(err.error, false);
              this.showLoader = false;
            },
          });
    } else {
      this.alertServices.showAlertError(" يجب ادخال جميع البيانات", false);
      this.showLoader = false;
    }
  }
}
